import { useState, useEffect } from "react";
import "./Recruitment.css";

function CreateLogin() {

  const [employees, setEmployees] = useState([]);
  const [users, setUsers] = useState([]);

  const [selectedEmp, setSelectedEmp] = useState("");
  const [username, setUsername] = useState("");
  const [designation, setDesignation] = useState("");

  /* =========================================
        PASSWORD HELPERS (INDUSTRY STANDARD)
     ========================================= */
  const generatePassword = () => {
    const chars =
      "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789@#$!";
    let pwd = "";
    for (let i = 0; i < 8; i++) {
      pwd += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return pwd;
  };

  const isValidPassword = (pwd) => {
    return /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@#$!]).{8,}$/.test(pwd);
  };

  /* =========================================
        LOAD EMPLOYEES + USERS (SAFE)
     ========================================= */
  useEffect(() => {
    const emp = JSON.parse(localStorage.getItem("employees")) || [];
    let usr = JSON.parse(localStorage.getItem("users")) || [];

    setEmployees(emp);

    // SAFETY CLEANUP
    const cleaned = usr.filter(
      u =>
        u &&
        u.empId &&
        u.username &&
        u.password &&
        u.role
    );

    if (cleaned.length !== usr.length) {
      localStorage.setItem("users", JSON.stringify(cleaned));
      usr = cleaned;
    }

    setUsers(usr);
  }, []);

  /* =========================================
        SELECT EMPLOYEE → AUTO FILL
     ========================================= */
  const handleSelect = (id) => {
    setSelectedEmp(id);

    const emp = employees.find(e => String(e.id) === String(id));
    if (emp) {
      setDesignation(emp.designation || "Employee");
      setUsername(emp.email || "");
    }
  };

  /* =========================================
        CREATE LOGIN (AUTO PASSWORD)
     ========================================= */
  const handleCreate = () => {
    if (!selectedEmp) return alert("Please select employee");
    if (!username.trim()) return alert("Username / Email required");

    const employee = employees.find(
      e => String(e.id) === String(selectedEmp)
    );

    if (!employee) return alert("Employee not found");

    // Prevent duplicate username
    const emailExists = users.some(
      u => u.username === username.trim()
    );
    if (emailExists) return alert("Email already exists");

    // Prevent duplicate login per employee
    const empExists = users.some(
      u => String(u.empId) === String(employee.id)
    );
    if (empExists) return alert("Login already exists for this employee");

    // Auto-generate strong password
    let newPassword = generatePassword();
    while (!isValidPassword(newPassword)) {
      newPassword = generatePassword();
    }

    const newUser = {
      empId: employee.id,
      name: employee.name || `${employee.firstName} ${employee.lastName}`,
      username: username.trim(),
      password: newPassword,
      role: "employee"
    };

    const updated = [...users, newUser];
    setUsers(updated);
    localStorage.setItem("users", JSON.stringify(updated));

    alert(
      `Login Created Successfully\n\nUsername: ${newUser.username}\nPassword: ${newPassword}`
    );

    setSelectedEmp("");
    setUsername("");
    setDesignation("");
  };

  return (
    <div className="designation-container">
      <h2>Create Login Credentials</h2>

      <div className="designation-form">

        {/* Select Employee */}
        <select
          value={selectedEmp}
          onChange={(e) => handleSelect(e.target.value)}
        >
          <option value="">Select Employee</option>
          {employees.map(emp => (
            <option key={emp.id} value={emp.id}>
              {emp.firstName} {emp.lastName}
            </option>
          ))}
        </select>

        {/* Designation */}
        <input
          type="text"
          value={designation}
          placeholder="Designation"
          disabled
        />

        {/* Username */}
        <input
          type="text"
          placeholder="Username / Email"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        {/* Password (AUTO) */}
        <input
          type="text"
          placeholder="Password will be auto-generated"
          disabled
        />

        <button onClick={handleCreate}>
          Create Login
        </button>
      </div>

      {/* USERS TABLE */}
      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Username</th>
            <th>Role</th>
          </tr>
        </thead>

        <tbody>
          {users.length === 0 ? (
            <tr>
              <td colSpan="4">No Users Created Yet</td>
            </tr>
          ) : (
            users.map((u, index) => (
              <tr key={u.empId}>
                <td>{index + 1}</td>
                <td>{u.name}</td>
                <td>{u.username}</td>
                <td>{u.role}</td>
              </tr>
            ))
          )}
        </tbody>
      </table>

    </div>
  );
}

export default CreateLogin;
